// Extract and validate input data
const inputData = $input.first().json;
const { input: userInput, sessionId, currentOrder } = inputData;

// Initialize session if not exists
if (!sessionId) {
  throw new Error('Session ID is required');
}

// Prepare data for next nodes
return [{
  json: {
    userInput: userInput || '',
    sessionId: sessionId,
    currentOrder: currentOrder || { items: [], total: 0 },
    timestamp: new Date().toISOString()
  }
}];

// Parse OpenAI response and prepare for product search
const aiResponse = $input.first().json;
let parsedIntent;

try {
  // Extract JSON from OpenAI response
  const content = aiResponse.choices[0].message.content;
  parsedIntent = JSON.parse(content);
} catch (error) {
  // Fallback parsing if JSON is malformed
  parsedIntent = {
    intent: 'clarification_needed',
    clarification: 'I could not understand your request. Please try again.',
    confidence: 0.1
  };
}

// Get session data
const sessionData = $('Validate Input').first().json;

return [{
  json: {
    ...sessionData,
    intent: parsedIntent.intent,
    products: parsedIntent.products || [],
    clarification: parsedIntent.clarification,
    confidence: parsedIntent.confidence || 0.5
  }
}];

// Process product search results and update cart
const searchResults = $input.all();
const intentData = $('Parse Intent').first().json;
const requestedProducts = intentData.products;

let cartUpdates = [];
let unavailableProducts = [];
let foundProducts = [];

// Process each requested product
requestProducts.forEach(requestedProduct => {
  const searchResult = searchResults.find(result => 
    result.json.name_similarity > 0.5 || 
    result.json.name.toLowerCase().includes(requestedProduct.name.toLowerCase())
  );

  if (searchResult && searchResult.json.availability === 'available') {
    foundProducts.push({
      id: searchResult.json.id,
      name: searchResult.json.name,
      price: searchResult.json.price,
      requestedQuantity: requestedProduct.quantity,
      unit: requestedProduct.unit,
      availableStock: searchResult.json.stock_quantity
    });
  } else if (searchResult) {
    unavailableProducts.push({
      requestedName: requestedProduct.name,
      actualName: searchResult.json.name,
      reason: 'out_of_stock'
    });
  } else {
    unavailableProducts.push({
      requestedName: requestedProduct.name,
      reason: 'not_found'
    });
  }
});

// Update current cart
let updatedCart = [...intentData.currentOrder.items];

foundProducts.forEach(product => {
  const existingItemIndex = updatedCart.findIndex(item => item.id === product.id);

  if (existingItemIndex >= 0) {
    updatedCart[existingItemIndex].quantity += product.requestedQuantity;
  } else {
    updatedCart.push({
      id: product.id,
      name: product.name,
      quantity: product.requestedQuantity,
      unitPrice: product.price,
      unit: product.unit
    });
  }
});

// Calculate total
const total = updatedCart.reduce((sum, item) => sum + (item.quantity * item.unitPrice), 0);

return [{
  json: {
    sessionId: intentData.sessionId,
    updatedCart: {
      items: updatedCart,
      total: total
    },
    foundProducts: foundProducts,
    unavailableProducts: unavailableProducts,
    action: 'cart_updated'
  }
}];

