// Handle cart check request
const intentData = $('Parse Intent').first().json;
const currentCart = intentData.currentOrder;

if (!currentCart.items || currentCart.items.length === 0) {
  return [{
    json: {
      sessionId: intentData.sessionId,
      response: "Your cart is currently empty. Would you like to add some items?",
      cart: currentCart,
      action: 'cart_checked'
    }
  }];
}

// Generate cart summary
let cartSummary = "Here's what's in your cart:\n\n";
currentCart.items.forEach((item, index) => {
  cartSummary += `${index + 1}. ${item.name} - ${item.quantity} ${item.unit || 'units'} @ ₹${item.unitPrice} each = ₹${item.quantity * item.unitPrice}\n`;
});

cartSummary += `\nTotal: ₹${currentCart.total}\n\nWould you like to add more items or confirm this order?";

return [{
  json: {
    sessionId: intentData.sessionId,
    response: cartSummary,
    cart: currentCart,
    action: 'cart_checked'
  }
}];

