// Generate order confirmation response
const orderData = $('Save Order').first().json;
const intentData = $('Parse Intent').first().json;

const confirmationMessage = `🎉 Order Confirmed!

Order ID: ${orderData.id}
Total: ₹${intentData.currentOrder.total}
Items: ${intentData.currentOrder.items.length}

Your order has been sent to our wholesaler and you'll receive a confirmation call shortly.

Thank you for your order!`;

return [{
  json: {
    sessionId: intentData.sessionId,
    response: confirmationMessage,
    orderId: orderData.id,
    action: 'order_confirmed',
    cart: { items: [], total: 0 } // Clear cart after confirmation
  }
}];

// Handle clarification needed
const intentData = $('Parse Intent').first().json;

const clarificationResponse = intentData.clarification || 
  "I didn't quite understand that. Could you please tell me what products you'd like to order? For example, you can say 'I need 5 kg rice and 2 liters oil'.";

return [{
  json: {
    sessionId: intentData.sessionId,
    response: clarificationResponse,
    cart: intentData.currentOrder,
    action: 'clarification_needed'
  }
}];
